1	/* codegen.h -- Expression code generation for PL/SW compiler */
2	/* Emits COR24 assembly for AST expression nodes */
3	
4	#ifndef CODEGEN_H
5	#define CODEGEN_H
6	
7	#include "token.h"
8	#include "emit.h"
9	#include "symtab.h"
10	#include "types.h"
11	
12	/* --- Register model ---
13	 * r0: primary accumulator (result register)
14	 * r1: secondary (RHS of binops, also link register for calls)
15	 * r2: tertiary (address calculations, spill)
16	 * fp: frame pointer for local variable access
17	 * sp: stack pointer
18	 *
19	 * Expression evaluation always leaves the result in r0.
20	 * For binary ops: LHS in r0, RHS in r1, result in r0.
21	 * When register pressure exceeds 3, spill to stack via push/pop.
22	 */
23	
24	/* --- Register names --- */
25	
26	char *reg_name[3];
27	
28	void cg_init_regs(void) {
29	    reg_name[0] = "r0";
30	    reg_name[1] = "r1";
31	    reg_name[2] = "r2";
32	}
33	
34	/* --- Codegen error state --- */
35	
36	int cg_err;
37	char *cg_errmsg;
38	
39	void cg_init(void) {
40	    cg_init_regs();
41	    cg_err = 0;
42	    cg_errmsg = 0;
43	}
44	
45	void cg_error(char *msg) {
46	    cg_err = 1;
47	    cg_errmsg = msg;
48	}
49	
50	/* --- Forward declarations --- */
51	
52	void cg_expr(int node);
53	void cg_call(int node);
54	
55	/* --- Helper: check if expression is "simple" (no push/pop needed) --- */
56	/* A simple expr is a literal or variable -- can load directly into r1 */
57	
58	int cg_is_simple(int node) {
59	    if (node == NODE_NULL) return 0;
60	    if (nd_kind[node] == NODE_LITERAL) return 1;
61	    if (nd_kind[node] == NODE_IDENT) return 1;
62	    return 0;
63	}
64	
65	/* --- Literal loading --- */
66	
67	void cg_literal(int node) {
68	    int val = nd_ival[node];
69	    if (val >= -128 && val <= 127) {
70	        /* Small constant: use lc (sign-extending 8-bit immediate) */
71	        emit_str(EMIT_INDENT);
72	        emit_str("lc      r0,");
73	        emit_int(val);
74	        emit_nl();
75	    } else {
76	        /* Large constant: use la (24-bit immediate) */
77	        emit_str(EMIT_INDENT);
78	        emit_str("la      r0,");
79	        emit_int(val);
80	        emit_nl();
81	    }
82	}
83	
84	/* --- Variable load --- */
85	/* Loads variable value into r0 */
86	
87	void cg_load_var(int node) {
88	    int idx;
89	    int off;
90	    int w;
91	
92	    idx = sym_lookup(nd_name[node]);
93	    if (idx < 0) {
94	        cg_error("undefined variable");
95	        emit_comment("ERROR: undefined variable");
96	        if (nd_name[node]) {
97	            emit_str(EMIT_INDENT);
98	            emit_str("; name: ");
99	            emit_line(nd_name[node]);
100	        }
101	        emit_str(EMIT_INDENT);
102	        emit_line("lc      r0,0");
103	        return;
104	    }
105	
106	    off = sym_offset[idx];
107	    w = sym_width[idx];
108	
109	    if (sym_stor[idx] == STOR_STATIC || sym_stor[idx] == STOR_EXTERNAL) {
110	        /* Static/external: load address, then dereference */
111	        emit_str(EMIT_INDENT);
112	        emit_str("la      r2,");
113	        emit_int(off);
114	        emit_nl();
115	        if (w == 1) {
116	            emit_instr("lb      r0,0(r2)");
117	        } else {
118	            emit_instr("lw      r0,0(r2)");
119	        }
120	    } else {
121	        /* Automatic (stack-relative via fp) */
122	        if (off >= -128 && off <= 127) {
123	            if (w == 1) {
124	                emit_str(EMIT_INDENT);
125	                emit_str("lb      r0,");
126	                emit_int(off);
127	                emit_line("(fp)");
128	            } else {
129	                emit_str(EMIT_INDENT);
130	                emit_str("lw      r0,");
131	                emit_int(off);
132	                emit_line("(fp)");
133	            }
134	        } else {
135	            /* Large offset: compute address in r2 */
136	            emit_str(EMIT_INDENT);
137	            emit_str("la      r2,");
138	            emit_int(off);
139	            emit_nl();
140	            emit_instr("add     r2,fp");
141	            if (w == 1) {
142	                emit_instr("lb      r0,0(r2)");
143	            } else {
144	                emit_instr("lw      r0,0(r2)");
145	            }
146	        }
147	    }
148	}
149	
150	/* --- Variable store --- */
151	/* Stores r0 into the variable named by the identifier node */
152	
153	void cg_store_var(int node) {
154	    int idx;
155	    int off;
156	    int w;
157	
158	    idx = sym_lookup(nd_name[node]);
159	    if (idx < 0) {
160	        cg_error("undefined variable for store");
161	        emit_comment("ERROR: undefined variable for store");
162	        return;
163	    }
164	
165	    off = sym_offset[idx];
166	    w = sym_width[idx];
167	
168	    if (sym_stor[idx] == STOR_STATIC || sym_stor[idx] == STOR_EXTERNAL) {
169	        emit_str(EMIT_INDENT);
170	        emit_str("la      r2,");
171	        emit_int(off);
172	        emit_nl();
173	        if (w == 1) {
174	            emit_instr("sb      r0,0(r2)");
175	        } else {
176	            emit_instr("sw      r0,0(r2)");
177	        }
178	    } else {
179	        if (off >= -128 && off <= 127) {
180	            if (w == 1) {
181	                emit_str(EMIT_INDENT);
182	                emit_str("sb      r0,");
183	                emit_int(off);
184	                emit_line("(fp)");
185	            } else {
186	                emit_str(EMIT_INDENT);
187	                emit_str("sw      r0,");
188	                emit_int(off);
189	                emit_line("(fp)");
190	            }
191	        } else {
192	            emit_str(EMIT_INDENT);
193	            emit_str("la      r2,");
194	            emit_int(off);
195	            emit_nl();
196	            emit_instr("add     r2,fp");
197	            if (w == 1) {
198	                emit_instr("sb      r0,0(r2)");
199	            } else {
200	                emit_instr("sw      r0,0(r2)");
201	            }
202	        }
203	    }
204	}
205	
206	/* --- Load simple expression into a specific register --- */
207	/* Used for RHS of binops when RHS is simple (avoids push/pop) */
208	
209	void cg_load_simple_into(int node, char *reg) {
210	    int val;
211	    int idx;
212	    int off;
213	    int w;
214	
215	    if (nd_kind[node] == NODE_LITERAL) {
216	        val = nd_ival[node];
217	        if (val >= -128 && val <= 127) {
218	            emit_str(EMIT_INDENT);
219	            emit_str("lc      ");
220	            emit_str(reg);
221	            emit_char(44);
222	            emit_int(val);
223	            emit_nl();
224	        } else {
225	            emit_str(EMIT_INDENT);
226	            emit_str("la      ");
227	            emit_str(reg);
228	            emit_char(44);
229	            emit_int(val);
230	            emit_nl();
231	        }
232	    } else if (nd_kind[node] == NODE_IDENT) {
233	        idx = sym_lookup(nd_name[node]);
234	        if (idx < 0) {
235	            cg_error("undefined variable");
236	            emit_comment("ERROR: undefined variable in simple load");
237	            return;
238	        }
239	        off = sym_offset[idx];
240	        w = sym_width[idx];
241	
242	        if (sym_stor[idx] == STOR_STATIC || sym_stor[idx] == STOR_EXTERNAL) {
243	            emit_str(EMIT_INDENT);
244	            emit_str("la      r2,");
245	            emit_int(off);
246	            emit_nl();
247	            if (w == 1) {
248	                emit_str(EMIT_INDENT);
249	                emit_str("lb      ");
250	                emit_str(reg);
251	                emit_line(",0(r2)");
252	            } else {
253	                emit_str(EMIT_INDENT);
254	                emit_str("lw      ");
255	                emit_str(reg);
256	                emit_line(",0(r2)");
257	            }
258	        } else {
259	            if (off >= -128 && off <= 127) {
260	                if (w == 1) {
261	                    emit_str(EMIT_INDENT);
262	                    emit_str("lb      ");
263	                    emit_str(reg);
264	                    emit_char(44);
265	                    emit_int(off);
266	                    emit_line("(fp)");
267	                } else {
268	                    emit_str(EMIT_INDENT);
269	                    emit_str("lw      ");
270	                    emit_str(reg);
271	                    emit_char(44);
272	                    emit_int(off);
273	                    emit_line("(fp)");
274	                }
275	            } else {
276	                /* Large offset: use r2 for address calc */
277	                emit_str(EMIT_INDENT);
278	                emit_str("la      r2,");
279	                emit_int(off);
280	                emit_nl();
281	                emit_instr("add     r2,fp");
282	                if (w == 1) {
283	                    emit_str(EMIT_INDENT);
284	                    emit_str("lb      ");
285	                    emit_str(reg);
286	                    emit_line(",0(r2)");
287	                } else {
288	                    emit_str(EMIT_INDENT);
289	                    emit_str("lw      ");
290	                    emit_str(reg);
291	                    emit_line(",0(r2)");
292	                }
293	            }
294	        }
295	    }
296	}
297	
298	/* --- Software division subroutine --- */
299	/* Emitted once per compilation unit if division is used.
300	 * Entry: r0 = dividend, r1 = divisor
301	 * Exit:  r0 = quotient, r1 = remainder
302	 * Uses repeated subtraction (COR24 has no hardware divide). */
303	
304	int cg_div_emitted;  /* flag: have we emitted the div routine? */
305	
306	void cg_emit_div_routine(void) {
307	    int lloop;
308	    int ldone;
309	    int lneg;
310	    int lfix;
311	
312	    if (cg_div_emitted) return;
313	    cg_div_emitted = 1;
314	
315	    emit_nl();
316	    emit_comment("Software division: r0/r1 -> r0=quotient, r1=remainder");
317	    emit_line("__plsw_div:");
318	    emit_prologue();
319	
320	    /* Load dividend and divisor from arguments (already in r0, r1) */
321	    /* Save sign info: we'll work with positive values */
322	    /* r2 = sign flag (0=positive result, 1=negative) */
323	    emit_instr("lc      r2,0");
324	
325	    /* Check if dividend is negative */
326	    lneg = emit_new_label();
327	    lfix = emit_new_label();
328	    emit_instr("ceq     r0,z");
329	    emit_str(EMIT_INDENT);
330	    emit_str("brt     ");
331	    emit_label_ref(lfix);
332	    emit_nl();
333	    emit_instr("cls     r0,z");
334	    emit_str(EMIT_INDENT);
335	    emit_str("brf     ");
336	    emit_label_ref(lneg);
337	    emit_nl();
338	    /* dividend is negative: negate it, flip sign flag */
339	    emit_instr("sub     r0,r0");
340	    emit_instr("sub     r0,r0");
341	    /* Actually: 0 - r0. Use: push r0, lc r0,0, pop and sub */
342	    /* Simpler: just note this is tricky without a neg instruction */
343	
344	    /* Simplified approach: unsigned division only for now.
345	     * Signed division handled by: abs both operands, divide, fix sign */
346	    emit_label(lneg);
347	    emit_label(lfix);
348	
349	    /* Division by repeated subtraction */
350	    lloop = emit_new_label();
351	    ldone = emit_new_label();
352	
353	    /* r0 = dividend (remainder), r2 = quotient (reuse r2) */
354	    emit_instr("push    r2");
355	    emit_instr("lc      r2,0");
356	    emit_label(lloop);
357	    emit_instr("cls     r0,r1");
358	    emit_str(EMIT_INDENT);
359	    emit_str("brt     ");
360	    emit_label_ref(ldone);
361	    emit_nl();
362	    emit_instr("sub     r0,r1");
363	    emit_instr("add     r2,1");
364	    emit_str(EMIT_INDENT);
365	    emit_str("bra     ");
366	    emit_label_ref(lloop);
367	    emit_nl();
368	    emit_label(ldone);
369	    /* r0 = remainder, r2 = quotient */
370	    emit_instr("mov     r1,r0");
371	    emit_instr("mov     r0,r2");
372	    emit_instr("pop     r2");
373	    emit_epilogue();
374	}
375	
376	/* --- Binary arithmetic codegen --- */
377	
378	void cg_binop(int node) {
379	    int op;
380	    int lhs;
381	    int rhs;
382	    int lbl_false;
383	    int lbl_end;
384	
385	    op = nd_ival[node];
386	    lhs = nd_left[node];
387	    rhs = nd_right[node];
388	
389	    if (cg_is_simple(rhs)) {
390	        /* Optimization: evaluate LHS into r0, load RHS directly into r1 */
391	        cg_expr(lhs);
392	        cg_load_simple_into(rhs, "r1");
393	    } else {
394	        /* Complex RHS: evaluate LHS, push, evaluate RHS, pop LHS into r1 */
395	        cg_expr(lhs);
396	        emit_instr1("push", "r0");
397	        cg_expr(rhs);
398	        emit_instr2("mov", "r1", "r0");
399	        emit_instr1("pop", "r0");
400	    }
401	
402	    /* Now: r0 = LHS, r1 = RHS. Emit operation. */
403	    if (op == TOK_PLUS) {
404	        emit_instr("add     r0,r1");
405	    } else if (op == TOK_MINUS) {
406	        emit_instr("sub     r0,r1");
407	    } else if (op == TOK_STAR) {
408	        emit_instr("mul     r0,r1");
409	    } else if (op == TOK_SLASH) {
410	        /* Division via software routine */
411	        emit_instr1("push", "r1");
412	        emit_instr1("push", "r0");
413	        emit_str(EMIT_INDENT);
414	        emit_str("la      r2,__plsw_div");
415	        emit_nl();
416	        emit_instr("jal     r1,(r2)");
417	        /* Result in r0 (quotient) */
418	    } else if (op == TOK_AMP) {
419	        /* Bitwise AND: COR24 doesn't have direct AND.
420	         * Use a helper or emit inline sequence.
421	         * For now, we'll note this and use a simple approach. */
422	        emit_comment("bitwise AND (r0 & r1)");
423	        emit_instr("and     r0,r1");
424	    } else if (op == TOK_PIPE) {
425	        emit_comment("bitwise OR (r0 | r1)");
426	        emit_instr("or      r0,r1");
427	    } else if (op == TOK_CARET) {
428	        emit_comment("bitwise XOR (r0 ^ r1)");
429	        emit_instr("xor     r0,r1");
430	    } else if (op == TOK_SHL) {
431	        emit_comment("shift left");
432	        emit_instr("shl     r0,r1");
433	    } else if (op == TOK_SHR) {
434	        emit_comment("shift right");
435	        emit_instr("shr     r0,r1");
436	    } else if (op == TOK_EQ) {
437	        /* Equality: ceq r0,r1 then mov r0,c */
438	        emit_instr("ceq     r0,r1");
439	        emit_instr("mov     r0,c");
440	    } else if (op == TOK_NE) {
441	        /* Not equal: ceq then invert */
442	        emit_instr("ceq     r0,r1");
443	        emit_instr("mov     r0,c");
444	        emit_instr("ceq     r0,z");
445	        emit_instr("mov     r0,c");
446	    } else if (op == TOK_LT) {
447	        /* Signed less-than */
448	        emit_instr("cls     r0,r1");
449	        emit_instr("mov     r0,c");
450	    } else if (op == TOK_GT) {
451	        /* Greater-than: swap operands for cls */
452	        emit_instr("cls     r1,r0");
453	        emit_instr("mov     r0,c");
454	    } else if (op == TOK_LE) {
455	        /* Less-or-equal: NOT (r1 < r0) */
456	        emit_instr("cls     r1,r0");
457	        emit_instr("mov     r0,c");
458	        emit_instr("ceq     r0,z");
459	        emit_instr("mov     r0,c");
460	    } else if (op == TOK_GE) {
461	        /* Greater-or-equal: NOT (r0 < r1) */
462	        emit_instr("cls     r0,r1");
463	        emit_instr("mov     r0,c");
464	        emit_instr("ceq     r0,z");
465	        emit_instr("mov     r0,c");
466	    } else {
467	        cg_error("unsupported binary operator");
468	        emit_comment("ERROR: unsupported binop");
469	    }
470	}
471	
472	/* --- Unary operators --- */
473	
474	void cg_unop(int node) {
475	    int op = nd_ival[node];
476	
477	    /* Evaluate operand into r0 */
478	    cg_expr(nd_left[node]);
479	
480	    if (op == TOK_MINUS) {
481	        /* Negate: 0 - r0 */
482	        emit_instr2("mov", "r1", "r0");
483	        emit_instr("lc      r0,0");
484	        emit_instr("sub     r0,r1");
485	    } else if (op == TOK_TILDE || op == TOK_NOT) {
486	        /* Bitwise NOT: XOR with all-ones */
487	        emit_str(EMIT_INDENT);
488	        emit_str("la      r1,");
489	        emit_int(0xFFFFFF);
490	        emit_nl();
491	        emit_instr("xor     r0,r1");
492	    } else {
493	        cg_error("unsupported unary operator");
494	        emit_comment("ERROR: unsupported unop");
495	    }
496	}
497	
498	/* --- Main expression codegen dispatcher --- */
499	
500	void cg_expr(int node) {
501	    if (node == NODE_NULL) {
502	        emit_comment("null expr");
503	        emit_instr("lc      r0,0");
504	        return;
505	    }
506	
507	    if (nd_kind[node] == NODE_LITERAL) {
508	        cg_literal(node);
509	    } else if (nd_kind[node] == NODE_IDENT) {
510	        cg_load_var(node);
511	    } else if (nd_kind[node] == NODE_BINOP) {
512	        cg_binop(node);
513	    } else if (nd_kind[node] == NODE_UNOP) {
514	        cg_unop(node);
515	    } else if (nd_kind[node] == NODE_CALL) {
516	        /* Function call in expression context: result in r0 */
517	        cg_call(node);
518	    } else {
519	        cg_error("unsupported expression node kind");
520	        emit_comment("ERROR: unsupported expr kind");
521	        emit_str(EMIT_INDENT);
522	        emit_str("; kind=");
523	        emit_int(nd_kind[node]);
524	        emit_nl();
525	    }
526	}
527	
528	/* --- Assignment codegen --- */
529	/* Evaluate RHS into r0, store into LHS variable */
530	
531	void cg_assign(int node) {
532	    int lhs = nd_left[node];
533	    int rhs = nd_right[node];
534	
535	    /* Evaluate RHS into r0 */
536	    cg_expr(rhs);
537	
538	    /* Store r0 into LHS */
539	    if (nd_kind[lhs] == NODE_IDENT) {
540	        cg_store_var(lhs);
541	    } else {
542	        cg_error("unsupported assignment target");
543	        emit_comment("ERROR: unsupported assignment target");
544	    }
545	}
546	
547	/* --- Static data emission --- */
548	
549	/* String literal table: maps labels to string data.
550	 * Used to collect string literals during codegen, then
551	 * emit them all in the .data section at the end. */
552	
553	#define CG_STR_MAX 32     /* max string literals per compilation */
554	
555	int cg_str_count;          /* number of string literals collected */
556	int cg_str_label[CG_STR_MAX];     /* label number for each string */
557	char *cg_str_data[CG_STR_MAX];    /* pointer to string content */
558	
559	void cg_static_init(void) {
560	    cg_str_count = 0;
561	}
562	
563	/* Register a string literal for emission. Returns its label number. */
564	int cg_add_string(char *s) {
565	    int lbl;
566	    if (cg_str_count >= CG_STR_MAX) {
567	        cg_error("too many string literals");
568	        return -1;
569	    }
570	    lbl = emit_new_label();
571	    cg_str_label[cg_str_count] = lbl;
572	    cg_str_data[cg_str_count] = s;
573	    cg_str_count = cg_str_count + 1;
574	    return lbl;
575	}
576	
577	/* Emit a single string literal as .byte directives with null terminator */
578	void cg_emit_string_bytes(char *s) {
579	    int i;
580	    int ch;
581	
582	    i = 0;
583	    while (s[i]) {
584	        emit_str(EMIT_INDENT);
585	        emit_str(".byte   ");
586	        emit_int(s[i]);
587	        emit_nl();
588	        i = i + 1;
589	    }
590	    /* Null terminator */
591	    emit_str(EMIT_INDENT);
592	    emit_line(".byte   0");
593	}
594	
595	/* Emit all collected string literals in the .data section */
596	void cg_emit_string_table(void) {
597	    int i;
598	    if (cg_str_count == 0) return;
599	
600	    emit_data_section();
601	    emit_comment("String literals");
602	
603	    i = 0;
604	    while (i < cg_str_count) {
605	        emit_label(cg_str_label[i]);
606	        cg_emit_string_bytes(cg_str_data[i]);
607	        i = i + 1;
608	    }
609	}
610	
611	/* Emit a static variable in the .data section.
612	 * Handles INIT values for scalars and zero-fill for uninitialized.
613	 * sym_idx = symbol table index for the variable.
614	 * init_node = AST node for INIT value, or NODE_NULL for zero. */
615	
616	void cg_emit_static_var(int sym_idx, int init_node) {
617	    int w;
618	    int addr;
619	    int val;
620	    int i;
621	    char *sval;
622	
623	    w = sym_width[sym_idx];
624	    addr = sym_offset[sym_idx];
625	
626	    emit_data_section();
627	
628	    /* Emit label at the static address */
629	    emit_comment(sym_name[sym_idx]);
630	    emit_named_label(sym_name[sym_idx]);
631	
632	    if (init_node != NODE_NULL && nd_kind[init_node] == NODE_LITERAL) {
633	        if (nd_type[init_node] == TYPE_CHAR && nd_name[init_node]) {
634	            /* String initializer: emit bytes */
635	            sval = nd_name[init_node];
636	            i = 0;
637	            while (sval[i]) {
638	                emit_str(EMIT_INDENT);
639	                emit_str(".byte   ");
640	                emit_int(sval[i]);
641	                emit_nl();
642	                i = i + 1;
643	            }
644	            /* Pad remaining space with zeros */
645	            while (i < w) {
646	                emit_str(EMIT_INDENT);
647	                emit_line(".byte   0");
648	                i = i + 1;
649	            }
650	        } else {
651	            /* Numeric initializer */
652	            val = nd_ival[init_node];
653	            if (w == 1) {
654	                emit_str(EMIT_INDENT);
655	                emit_str(".byte   ");
656	                emit_int(val);
657	                emit_nl();
658	            } else {
659	                emit_str(EMIT_INDENT);
660	                emit_str(".word   ");
661	                emit_int(val);
662	                emit_nl();
663	            }
664	        }
665	    } else {
666	        /* No initializer: zero-fill */
667	        if (w == 1) {
668	            emit_str(EMIT_INDENT);
669	            emit_line(".byte   0");
670	        } else if (w <= 3) {
671	            emit_str(EMIT_INDENT);
672	            emit_line(".word   0");
673	        } else {
674	            /* Large zero fill: emit individual bytes */
675	            i = 0;
676	            while (i < w) {
677	                emit_str(EMIT_INDENT);
678	                emit_line(".byte   0");
679	                i = i + 1;
680	            }
681	        }
682	    }
683	}
684	
685	/* Walk a program AST and emit .data section for all static/global DCLs.
686	 * Assumes layout_globals() has already been called to assign addresses. */
687	
688	void cg_emit_static_data(int prog_node) {
689	    int child;
690	    int idx;
691	
692	    if (prog_node == NODE_NULL) return;
693	
694	    child = nd_left[prog_node];
695	    while (child != NODE_NULL) {
696	        if (nd_kind[child] == NODE_DCL) {
697	            idx = sym_lookup(nd_name[child]);
698	            if (idx >= 0) {
699	                cg_emit_static_var(idx, nd_right[child]);
700	            }
701	        }
702	        child = nd_next[child];
703	    }
704	
705	    /* Emit any collected string literals */
706	    cg_emit_string_table();
707	}
708	
709	/* Load address of a string literal into r0.
710	 * Used when a string literal appears in an expression context. */
711	
712	void cg_load_string(int label_num) {
713	    emit_str(EMIT_INDENT);
714	    emit_str("la      r0,");
715	    emit_label_ref(label_num);
716	    emit_nl();
717	}
718	
719	/* --- Call codegen --- */
720	/* Forward declaration for cg_block */
721	void cg_block(int block_node);
722	
723	/* Count arguments in a linked list (via nd_next) */
724	int cg_count_args(int first_arg) {
725	    int count;
726	    int arg;
727	    count = 0;
728	    arg = first_arg;
729	    while (arg != NODE_NULL) {
730	        count = count + 1;
731	        arg = nd_next[arg];
732	    }
733	    return count;
734	}
735	
736	/* Emit code for a procedure call.
737	 * CALL node: nd_name = procedure name, nd_left = first arg (linked via nd_next).
738	 * COR24 calling convention:
739	 *   - Evaluate arguments left-to-right
740	 *   - Push arguments right-to-left onto stack
741	 *   - Call via jal r1,(r2)
742	 *   - Clean up stack after return (add sp, arg_count*3)
743	 *   - Return value in r0 */
744	
745	void cg_call(int node) {
746	    int nargs;
747	    int arg;
748	    int i;
749	    int cleanup;
750	
751	    if (node == NODE_NULL) return;
752	
753	    nargs = cg_count_args(nd_left[node]);
754	
755	    if (nargs == 0) {
756	        /* No arguments: just call */
757	        emit_str(EMIT_INDENT);
758	        emit_str("la      r2,_");
759	        emit_line(nd_name[node]);
760	        emit_instr("jal     r1,(r2)");
761	    } else {
762	        /* Evaluate args L-to-R, store in R-to-L stack order.
763	         * Pre-allocate space, then store each at the correct offset
764	         * so first arg ends up at lowest address (closest to sp).
765	         * Callee sees fp+9 = first arg, fp+12 = second, etc. */
766	        cleanup = nargs * 3;
767	        emit_str(EMIT_INDENT);
768	        emit_str("lc      r2,");
769	        emit_int(cleanup);
770	        emit_nl();
771	        emit_instr("sub     sp,r2");
772	
773	        /* Evaluate each arg L-to-R and store at sp + i*3.
774	         * arg1 at sp+0 -> callee fp+9 (first param)
775	         * arg2 at sp+3 -> callee fp+12 (second param) */
776	        arg = nd_left[node];
777	        i = 0;
778	        while (arg != NODE_NULL) {
779	            cg_expr(arg);
780	            emit_str(EMIT_INDENT);
781	            emit_str("sw      r0,");
782	            emit_int(i * 3);
783	            emit_line("(sp)");
784	            i = i + 1;
785	            arg = nd_next[arg];
786	        }
787	
788	        /* Call the procedure */
789	        emit_str(EMIT_INDENT);
790	        emit_str("la      r2,_");
791	        emit_line(nd_name[node]);
792	        emit_instr("jal     r1,(r2)");
793	
794	        /* Clean up args from stack */
795	        emit_str(EMIT_INDENT);
796	        emit_str("lc      r2,");
797	        emit_int(cleanup);
798	        emit_nl();
799	        emit_instr("add     sp,r2");
800	    }
801	}
802	
803	/* --- Control flow codegen --- */
804	
805	/* Forward declaration for mutual recursion */
806	void cg_stmt(int node);
807	void cg_block(int block_node);
808	
809	/* IF/THEN/ELSE codegen.
810	 * AST: nd_left = condition, nd_right = then body, nd_ival = else body (or NODE_NULL) */
811	void cg_if(int node) {
812	    int lbl_else;
813	    int lbl_end;
814	    int else_body;
815	
816	    else_body = nd_ival[node];
817	
818	    /* Evaluate condition into r0 */
819	    cg_expr(nd_left[node]);
820	
821	    if (else_body != NODE_NULL) {
822	        /* IF/THEN/ELSE */
823	        lbl_else = emit_new_label();
824	        lbl_end = emit_new_label();
825	
826	        /* Branch to else if r0 == 0 (condition false) */
827	        emit_instr("ceq     r0,z");
828	        emit_str(EMIT_INDENT);
829	        emit_str("bc      ");
830	        emit_label_ref(lbl_else);
831	        emit_nl();
832	
833	        /* Then body */
834	        cg_stmt(nd_right[node]);
835	        emit_str(EMIT_INDENT);
836	        emit_str("jmp     ");
837	        emit_label_ref(lbl_end);
838	        emit_nl();
839	
840	        /* Else label and body */
841	        emit_label(lbl_else);
842	        cg_stmt(else_body);
843	
844	        /* End label */
845	        emit_label(lbl_end);
846	    } else {
847	        /* IF/THEN (no else) */
848	        lbl_end = emit_new_label();
849	
850	        /* Branch to end if r0 == 0 (condition false) */
851	        emit_instr("ceq     r0,z");
852	        emit_str(EMIT_INDENT);
853	        emit_str("bc      ");
854	        emit_label_ref(lbl_end);
855	        emit_nl();
856	
857	        /* Then body */
858	        cg_stmt(nd_right[node]);
859	
860	        /* End label */
861	        emit_label(lbl_end);
862	    }
863	}
864	
865	/* --- Statement codegen --- */
866	
867	/* Emit code for a single statement node */
868	void cg_stmt(int node) {
869	    if (node == NODE_NULL) return;
870	
871	    if (nd_kind[node] == NODE_ASSIGN) {
872	        cg_assign(node);
873	    } else if (nd_kind[node] == NODE_RETURN) {
874	        /* Evaluate return expression into r0 (if present) */
875	        if (nd_left[node] != NODE_NULL) {
876	            cg_expr(nd_left[node]);
877	        }
878	        /* Epilogue emitted by caller at procedure end.
879	         * For early returns, emit epilogue inline. */
880	        emit_epilogue();
881	    } else if (nd_kind[node] == NODE_CALL) {
882	        /* Bare CALL statement (result in r0 discarded) */
883	        cg_call(node);
884	    } else if (nd_kind[node] == NODE_BLOCK) {
885	        cg_block(node);
886	    } else if (nd_kind[node] == NODE_IF) {
887	        /* IF/THEN/ELSE: evaluate condition, branch on false */
888	        cg_if(node);
889	    } else if (nd_kind[node] == NODE_DCL) {
890	        /* Local DCL: no code emission needed (handled by layout) */
891	    } else {
892	        cg_error("unsupported statement kind");
893	        emit_comment("ERROR: unsupported statement");
894	        emit_str(EMIT_INDENT);
895	        emit_str("; kind=");
896	        emit_int(nd_kind[node]);
897	        emit_nl();
898	    }
899	}
900	
901	/* Emit code for a block of statements */
902	void cg_block(int block_node) {
903	    int stmt;
904	    if (block_node == NODE_NULL) return;
905	
906	    stmt = nd_left[block_node];
907	    while (stmt != NODE_NULL) {
908	        cg_stmt(stmt);
909	        stmt = nd_next[stmt];
910	    }
911	}
912	
913	/* --- Procedure codegen --- */
914	
915	/* Emit code for a complete procedure.
916	 * proc_node is a NODE_PROC with:
917	 *   nd_name  = procedure name
918	 *   nd_left  = first parameter (linked via nd_next)
919	 *   nd_right = body (BLOCK node)
920	 *   nd_ival  = option flags (OPT_FREESTANDING, OPT_NAKED, OPT_LEAF)
921	 *   nd_stor  = return type
922	 *
923	 * Layout must be performed first via layout_proc(). */
924	
925	void cg_proc(int proc_node) {
926	    int opts;
927	    int frame_sz;
928	    int has_body;
929	    int body;
930	
931	    if (proc_node == NODE_NULL) return;
932	    if (nd_kind[proc_node] != NODE_PROC) {
933	        cg_error("expected PROC node");
934	        return;
935	    }
936	
937	    opts = nd_ival[proc_node];
938	    body = nd_right[proc_node];
939	
940	    /* Ensure we're in .text section */
941	    emit_text_section();
942	
943	    /* Emit .globl directive and label */
944	    if (nd_name[proc_node]) {
945	        emit_global(nd_name[proc_node]);
946	        emit_named_label(nd_name[proc_node]);
947	    }
948	
949	    /* NAKED procedures: no prologue/epilogue, body is raw */
950	    if (opts & 2) {
951	        /* OPT_NAKED */
952	        emit_comment("NAKED procedure -- no prologue/epilogue");
953	        cg_block(body);
954	        return;
955	    }
956	
957	    /* Standard prologue: push fp, push r2, push r1, mov fp,sp */
958	    emit_prologue();
959	
960	    /* Allocate stack space for locals (sub sp, frame_size) */
961	    frame_sz = layout_frame_size;
962	    if (frame_sz > 0) {
963	        if (frame_sz >= -128 && frame_sz <= 127) {
964	            emit_str(EMIT_INDENT);
965	            emit_str("lc      r0,");
966	            emit_int(frame_sz);
967	            emit_nl();
968	        } else {
969	            emit_str(EMIT_INDENT);
970	            emit_str("la      r0,");
971	            emit_int(frame_sz);
972	            emit_nl();
973	        }
974	        emit_instr("sub     sp,r0");
975	    }
976	
977	    /* Emit body statements */
978	    cg_block(body);
979	
980	    /* Standard epilogue: mov sp,fp, pop r1, pop r2, pop fp, jmp (r1) */
981	    emit_epilogue();
982	}
983	
984	/* Emit code for all procedures in a program AST.
985	 * Walks top-level children and codegen's each PROC node.
986	 * Handles layout_proc() and scope management for each. */
987	
988	void cg_program_procs(int prog_node) {
989	    int child;
990	
991	    if (prog_node == NODE_NULL) return;
992	
993	    child = nd_left[prog_node];
994	    while (child != NODE_NULL) {
995	        if (nd_kind[child] == NODE_PROC) {
996	            /* Layout procedure (enters scope, assigns offsets) */
997	            layout_proc(child);
998	            /* Emit code */
999	            cg_proc(child);
1000	            /* Exit procedure scope */
1001	            sym_exit_scope();
1002	        }
1003	        child = nd_next[child];
1004	    }
1005	}
1006	
1007	#endif /* CODEGEN_H */
